const { ChromaClient } = require\('chromadb'\);
require\('dotenv'\).config\({ path: '.env.local' }\);

async function getEmbedding\(text\) {
  const res = await fetch\('https://dashscope.aliyuncs.com/compatible-mode/v1/embeddings', {
    method: 'POST',
    headers: { 'Authorization': 'Bearer ' + process.env.DASHSCOPE_API_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify\({ model: 'text-embedding-v3', input: text }\)
  }\);
  const data = await res.json\(\);
  return data.data[0].embedding;
}

async function test\(\) {
  const client = new ChromaClient\({ path: 'http://localhost:8000' }\);
  const col = await client.getOrCreateCollection\({ name: 'finance-docs' }\);

  const emb = await getEmbedding\('金渐成投资建议'\);
  console.log\('Embedding dim:', emb.length\);

  const results = await col.query\({ queryEmbeddings: [emb], nResults: 3 }\);
  console.log\('Results count:', results.documents?.[0]?.length\);
  console.log\('Docs:', results.documents?.[0]?.map\(d => d?.substring\(0, 80\)\)\);
}
test\(\).catch\(e => console.error\(e\)\);
" 2>&1)

